import * as AasStringification from "../src/stringification";
import * as AasTypes from "../src/types";

test("Result stringification round-trip Ok", () => {
  const literal = AasTypes.Result.Ok;

  const text = AasStringification.mustResultToString(literal);
  expect(text).toStrictEqual("ok");

  const nullableText = AasStringification.resultToString(literal);
  expect(nullableText).toStrictEqual("ok");

  const parsed = AasStringification.resultFromString(text);
  expect(parsed).toStrictEqual(literal);
});

test("Result stringification round-trip Fail", () => {
  const literal = AasTypes.Result.Fail;

  const text = AasStringification.mustResultToString(literal);
  expect(text).toStrictEqual("fail");

  const nullableText = AasStringification.resultToString(literal);
  expect(nullableText).toStrictEqual("fail");

  const parsed = AasStringification.resultFromString(text);
  expect(parsed).toStrictEqual(literal);
});

test("Result from invalid string", () => {
  const parsed = AasStringification.resultFromString(
    "invalid-literal"
  );

  expect(parsed).toBeNull();
});

test("Result invalid literal to string", () => {
  // The number 9007199254740991 is the maximum safe integer.
  const invalidLiteral = <AasTypes.Result>9007199254740991;

  expect(AasStringification.resultToString(invalidLiteral)).toBeNull();
  expect(() => AasStringification.mustResultToString(invalidLiteral)).toThrow();
});

